import React, { useEffect, useState } from "react";
import "./Products.css";
import axios from "axios";
import { Link } from "react-router-dom";

function Products({ cart, updateCart }) {
  const [products, setProducts] = useState([]);

  useEffect(() => {
    axios
      .get("http://localhost:5000/api/products")
      .then((res) => {
        setProducts(res.data);
      })
      .catch((err) => {
        console.error("Failed to fetch products:", err);
      });
  }, []);

  // 👉 Category filter
  const shirts = products.filter((p) => p.category === "shirt");
  const pants = products.filter((p) => p.category === "pants");
  const innerwears = products.filter((p) => p.category === "innerwear");

  // 👉 Add to Cart handler
  const addToCart = (item) => {
    const newItem = {
      ...item,
      quantity: 1,
      selectedSize: item.sizes ? item.sizes[0] : "Free Size",
    };

    const alreadyInCart = cart.find(
      (cartItem) =>
        cartItem._id === newItem._id &&
        cartItem.selectedSize === newItem.selectedSize
    );

    let updatedCart;
    if (alreadyInCart) {
      updatedCart = cart.map((cartItem) =>
        cartItem._id === newItem._id &&
        cartItem.selectedSize === newItem.selectedSize
          ? { ...cartItem, quantity: cartItem.quantity + 1 }
          : cartItem
      );
    } else {
      updatedCart = [...cart, newItem];
    }

    updateCart(updatedCart);
    alert(`${item.name} added to cart 🛒`);
  };

  return (
    <div className="products-container">
      {/* Shirts */}
      <h1 className="section-title">🧥 Shirts</h1>
      <div className="product-grid">
        {shirts.map((item) => (
          <div key={item._id} className="product-card">
            <Link to={`/product/${item._id}`} className="product-card-link">
              <img src={item.image} alt={item.name} />
              <h3>{item.name}</h3>
              <p className="price">₹{item.price}</p>
            </Link>
            <button className="cart-btn" onClick={() => addToCart(item)}>
              Add to Cart
            </button>
          </div>
        ))}
      </div>

      {/* Pants */}
      <h1 className="section-title">👖 Pants</h1>
      <div className="product-grid">
        {pants.map((item) => (
          <div key={item._id} className="product-card">
            <Link to={`/product/${item._id}`} className="product-card-link">
              <img src={item.image} alt={item.name} />
              <h3>{item.name}</h3>
              <p className="price">₹{item.price}</p>
            </Link>
            <button className="cart-btn" onClick={() => addToCart(item)}>
              Add to Cart
            </button>
          </div>
        ))}
      </div>

      {/* Innerwear */}
      <h1 className="section-title">🩲 Innerwear</h1>
      <div className="product-grid">
        {innerwears.map((item) => (
          <div key={item._id} className="product-card">
            <Link to={`/product/${item._id}`} className="product-card-link">
              <img src={item.image} alt={item.name} />
              <h3>{item.name}</h3>
              <p className="price">₹{item.price}</p>
            </Link>
            <button className="cart-btn" onClick={() => addToCart(item)}>
              Add to Cart
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Products;
